"use client";
import { useEffect, useState } from "react";
import { Bell, Check, CheckCheck } from "lucide-react";
import { motion } from "framer-motion";
import { formatDate } from "@/lib/utils";

interface Notif { id: string; type: string; title: string; body: string; read: boolean; createdAt: string }

const typeIcon: Record<string, string> = { ASSIGNMENT: "📋", HOURS_APPROVED: "⏰", EMERGENCY: "🚨", DONATION: "💰", BADGE: "🏅", EVENT: "📅" };

export default function NotificationsPage() {
  const [notifs, setNotifs] = useState<Notif[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch("/api/notifications").then(r => r.json()).then(d => { setNotifs(Array.isArray(d) ? d : []); setLoading(false); });
  }, []);

  const markAllRead = async () => {
    await fetch("/api/notifications", { method: "PATCH" });
    setNotifs(prev => prev.map(n => ({ ...n, read: true })));
  };

  return (
    <div className="max-w-3xl mx-auto space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold flex items-center gap-2" style={{ fontFamily: "Plus Jakarta Sans", color: "var(--ink)" }}>
            <Bell size={28} style={{ color: "var(--green-dark)" }} /> Notifications
          </h1>
          <p className="text-sm mt-1" style={{ color: "var(--muted)" }}>{notifs.filter(n => !n.read).length} unread</p>
        </div>
        {notifs.some(n => !n.read) && (
          <button onClick={markAllRead} className="flex items-center gap-1.5 text-sm font-medium px-3 py-1.5 rounded-lg border"
            style={{ borderColor: "var(--green-light)", color: "var(--green-dark)" }}>
            <CheckCheck size={14} /> Mark all read
          </button>
        )}
      </div>

      <div className="glass rounded-2xl overflow-hidden">
        {loading ? (
          <div className="p-8 text-center text-sm" style={{ color: "var(--muted)" }}>Loading…</div>
        ) : notifs.length === 0 ? (
          <div className="p-16 text-center">
            <Bell size={40} className="mx-auto mb-4" style={{ color: "var(--muted)" }} />
            <p className="font-bold" style={{ color: "var(--ink)" }}>All caught up!</p>
            <p className="text-sm" style={{ color: "var(--muted)" }}>No notifications yet.</p>
          </div>
        ) : (
          <div className="divide-y" style={{ divideColor: "var(--green-pale)" }}>
            {notifs.map((n, i) => (
              <motion.div key={n.id} initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: i * 0.04 }}
                className={`flex items-start gap-4 px-6 py-4 transition-colors ${n.read ? "" : "bg-green-50/60"}`}>
                <span className="text-xl mt-0.5">{typeIcon[n.type] ?? "🔔"}</span>
                <div className="flex-1">
                  <p className="font-semibold text-sm" style={{ color: "var(--ink)" }}>{n.title}</p>
                  <p className="text-xs mt-0.5 leading-relaxed" style={{ color: "var(--muted)" }}>{n.body}</p>
                  <p className="text-[10px] mt-1" style={{ color: "var(--green-light)" }}>{formatDate(n.createdAt)}</p>
                </div>
                {!n.read && <div className="w-2 h-2 rounded-full mt-2 flex-shrink-0" style={{ background: "var(--green-accent)" }} />}
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
